// Parse endorsement type and determine processing
const payload = $input.first().json.payload;
const endorsementType = payload.endorsement_type;

let processingType = 'standard';
let requiresApproval = false;
let priority = 'medium';
let autoProcess = false;

switch(endorsementType) {
  case 'add_driver':
  case 'add_vehicle':
  case 'add_location':
    processingType = 'addition';
    requiresApproval = true;
    priority = 'high';
    break;
  case 'remove_driver':
  case 'remove_vehicle':
  case 'remove_location':
    processingType = 'removal';
    autoProcess = true;
    break;
  case 'coverage_increase':
    processingType = 'coverage_change';
    requiresApproval = true;
    priority = 'high';
    break;
  case 'coverage_decrease':
    processingType = 'coverage_change';
    autoProcess = true;
    break;
  case 'address_change':
  case 'name_change':
    processingType = 'info_update';
    autoProcess = true;
    break;
  case 'additional_insured':
    processingType = 'certificate';
    priority = 'high';
    autoProcess = true;
    break;
}

return {
  ticket_id: $input.first().json.entity_id,
  agency_workspace_id: $input.first().json.agency_workspace_id,
  endorsement_type: endorsementType,
  processing_type: processingType,
  requires_approval: requiresApproval,
  auto_process: autoProcess,
  priority: priority,
  policy_id: payload.policy_id,
  account_id: payload.account_id
};
